#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

inline float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(
    __global float *input,
    __global float *output,
    __global float *weights,
    __global float *partial_sum,
    __local float *local_mem1,
    __local float *local_mem2,
    const int n1,
    const int n2)
{
    int block_id = get_global_id(1) / BLOCK_SIZE;
    int j = get_global_id(1) % BLOCK_SIZE + 1;

    if (j <= n2 && block_id <= n1 / BLOCK_SIZE) {
        float sum = 0.0f;
        int start_k = block_id * BLOCK_SIZE;
        int end_k = start_k + BLOCK_SIZE;

        for (int k = start_k; k < end_k && k <= n1; k++) {
            sum += weights[k * (n2 + 1) + j] * input[k];
        }

        partial_sum[block_id * WIDTH + (j - 1)] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(
    __global float *delta,
    const int ndelta,
    __global float *ly,
    const int nly,
    __global float *w,
    __global float *oldw)
{
    int j = get_global_id(1) % ndelta + 1;
    int k = get_global_id(0);

    if (j <= ndelta && k <= nly) {
        int idx = k * (ndelta + 1) + j;
        float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[idx]);
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
